import React from 'react';

const AboutMe = () => {
  const items = [
    {
      label: 'Age',
      value: '19 years old',
    },
    {
      label: 'Hobbies',
      value: 'Watching anime, Working out, and Playing videogames',
      images: [
        { src: 'https://i.redd.it/both-of-these-fall-under-the-carried-by-animation-v0-gjip3tvumfpe1.jpg', alt: 'Anime' },
        { src: 'https://img.joomcdn.net/3951999955bde0c8ac0a989a3d481890d9b794cd_original.jpeg', alt: 'Bodybuilding' },
        { src: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ0WSAO7K7N54BRF4t5rcez6eaZuHPYT88DMA&s', alt: 'Videogame' },
      ],
    },
  ];

  return (
    <section
      id="About-Me"
      style={{ background: '#112240', fontFamily: "'Orbitron', sans-serif" }}
      className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
    >
      <h1 className="text-white text-4xl font-bold mb-12">More About Me</h1>

      <div className="w-full max-w-3xl flex flex-col gap-6">
        {items.map((item, i) => (
          <div
            key={i}
            style={{
              background: '#f8f9fa',
              borderLeft: '5px solid #0d6efd',
              borderRadius: '12px',
              padding: '20px',
            }}
          >
            <p style={{ color: '#0b1f3a' }}>
              <b style={{ color: '#0d6efd' }}>{item.label}:</b>{' '}
              {item.value}
            </p>

            {item.images && (
              <div style={{ display: 'flex', gap: '10px', marginTop: '12px' }}>
                {item.images.map((img, j) => (
                  <img
                    key={j}
                    src={img.src}
                    alt={img.alt}
                    width="140"
                    style={{ borderRadius: '10px', border: '1px solid #0d6efd33' }}
                  />
                ))}
              </div>
            )}
          </div>
        ))}
      </div>
    </section>
  );
};

export default AboutMe;
